import React from 'react';
import JobCard from './JobCard';

const JobList = ({ jobs, variant, onSelectJob }) => {
    return (
        <div style={containerStyle}>
            {jobs.map(job => (
                // Tambahkan 'key' di sini. 
                // Kita menggunakan job.id karena data kita berasal dari database
                <div key={job.id}> 
                    <JobCard 
                        job={job} 
                        isFull={variant === 'full'} 
                        onClick={() => onSelectJob && onSelectJob(job)}
                    />
                </div>
            ))}
        </div>
    );

    return (
        <div style={containerStyle}>
            {jobList.map(job => (
                // Pastikan 'job.id' unik. Jika data dari backend, gunakan 'job.id'
                <div key={job.id}> 
                    <JobCard 
                        job={job} 
                        isFull={variant === 'full'} 
                        onClick={() => onSelectJob && onSelectJob(job)}
                    />
                </div>
            ))}
        </div>
    );
};

export default JobList;
